const error = $json.execution?.error || $json.error || {};
const execution = $json.execution || {};
const workflow = $json.workflow || {};
const data = execution.data || {};
const runData = data.resultData?.runData || {};
const nodeNames = Object.keys(runData);
const lastNode = nodeNames[nodeNames.length - 1] || error.node?.name || '';
const payload = {
  workflow_id: workflow.id || execution.workflowId || '',
  workflow_nome: workflow.name || execution.workflowName || '',
  execution_id: execution.id || '',
  node_nome: error.node?.name || lastNode,
  erro_tipo: error.name || error.type || 'Error',
  erro_mensagem: error.message || execution.error?.message || 'Erro sem mensagem',
  telefone: String(
    execution.data?.resultData?.lastNodeExecutedPhone
    || $json.telefone
    || ''
  ).replace(/\D/g, ''),
  candidato_id: Number($json.candidato_id || 0) || null,
  payload: $json,
};
return { json: payload };
